import React, { useEffect, useState } from "react";
import "./PersonalAIMentor.css";

const firstMessages = {
  INTP: "გამარჯობა 😊 მოდი ერთად გავაანალიზოთ შენი ძლიერი მხარეები.",
  ENFP: "გამარჯობა 🌟 როგორ შემიძლია დაგეხმარო უკეთ გაიცნო შენი შესაძლებლობები?",
  ESFJ: "გამარჯობა 💛 გინდა ვისაუბროთ შენს ურთიერთობებსა და მიზნებზე?",
  DEFAULT: "გამარჯობა 😊 როგორ შემიძლია დაგეხმარო, რომ უკეთ გაიცნო შენი ფსიქოტიპი?"
};

export default function PersonalAIMentor({ user }) {
  const [messages, setMessages] = useState([]);
  const [input, setInput] = useState("");

  const mbti = user?.mbti || "DEFAULT"; // assume user object has mbti field
  const token = localStorage.getItem("auth_token");

  // ჩატის აღდგენა სერვერიდან
  useEffect(() => {
    if (!user || !token) return;

    fetch("http://localhost:5000/api/chat-reply/history", {
      headers: {
        Authorization: `Bearer ${token}`,
      },
    })
      .then(res => res.json())
      .then(data => {
        if (data.history && data.history.length > 0) {
          setMessages(data.history);
        } else {
          const first = firstMessages[mbti] || firstMessages.DEFAULT;
          setMessages([{ role: "ai", text: first }]);
        }
      })
      .catch(() => {
        const first = firstMessages[mbti] || firstMessages.DEFAULT;
        setMessages([{ role: "ai", text: first }]);
      });
  }, [mbti, user, token]);

  const sendMessage = () => {
    if (!input.trim() || !token) return;

    const newUserMsg = { role: "user", text: input };
    setMessages(prev => [...prev, newUserMsg]);

    fetch("http://localhost:5000/api/chat-reply/reply", {
      method: "POST",
      headers: {
        "Content-Type": "application/json",
        Authorization: `Bearer ${token}`,
      },
      body: JSON.stringify({
        message: input,
        type: mbti,
      }),
    })
      .then(res => res.json())
      .then(data => {
        setMessages(prev => [...prev, { role: "ai", text: data.reply }]);
      })
      .catch(() => {
        setMessages(prev => [
          ...prev,
          { role: "ai", text: "უკაცრავად, ახლა ჩატი ხელმისაწვდომი არ არის 😅" }
        ]);
      });

    setInput("");
  };

  // ახალი ჩატის დაწყება
  const newChat = async () => {
    if (!token) return;

    const first = firstMessages[mbti] || firstMessages.DEFAULT;
    setMessages([{ role: "ai", text: first }]);

    await fetch("http://localhost:5000/api/chat-reply/reset", {
      method: "POST",
      headers: {
        "Content-Type": "application/json",
        Authorization: `Bearer ${token}`,
      },
    });
  };

  return (
    <div className="ai-mentor">
      <div className="ai-header">
        Personal AI Mentor
        <button className="new-chat-btn" onClick={newChat}>
          New Chat
        </button>
      </div>

      <div className="ai-messages">
        {messages.map((m, i) => (
          <div key={i} className={`msg ${m.role}`}>
            {m.text}
          </div>
        ))}
      </div>

      <div className="ai-input">
        <textarea
          value={input}
          onChange={e => setInput(e.target.value)}
          onKeyDown={e => {
            if (e.key === "Enter" && !e.shiftKey) {
              e.preventDefault();
              sendMessage();
            }
          }}
          placeholder="მომწერე..."
          rows="1"
          className="ai-textarea"
        />
        <button onClick={sendMessage}>გაგზავნა</button>
      </div>
    </div>
  );
}
